    32→
    33→function registerIpcHandlers() {
    34→  ipcMain.handle('agent:list', async () => orchestrator.listAgents());
    35→  ipcMain.handle('engine:list', async () => orchestrator.getEngineStatuses());
    36→  ipcMain.handle('state:get', async () => orchestrator.getState());
    37→  ipcMain.handle('agent:create', async (_event, payload) => orchestrator.createAgent(payload));
    38→  ipcMain.handle('agent:remove', async (_event, agentId) => orchestrator.removeAgent(agentId));
    39→  ipcMain.handle('run:start', async (_event, payload) => orchestrator.startRun(payload));
    40→  ipcMain.handle('run:cancel', async (_event, runId) => orchestrator.cancelRun(runId));
    41→  ipcMain.handle('run:relay', async (_event, payload) => orchestrator.startRelay(payload));
    42→  ipcMain.handle('workspace:diff', async (_event, agentId) => orchestrator.getAgentDiff(agentId));
    43→}
    44→
    45→// ═══════════════════════════════════════════════════════════════
    46→// WEBSOCKET BRIDGE — connects Claude Code ↔ ClawCraft UI
    47→// Port 9477, JSON protocol
    48→// ═══════════════════════════════════════════════════════════════
    49→function startBridge() {
    50→  wss = new WebSocketServer({ port: BRIDGE_PORT });
    51→  console.log(`[Bridge] WebSocket server listening on ws://localhost:${BRIDGE_PORT}`);
    52→
    53→  wss.on('connection', (ws) => {
    54→    console.log('[Bridge] Client connected');
    55→    ws.send(JSON.stringify({ type: 'connected', message: 'ClawCraft bridge ready' }));
    56→
    57→    // Forward orchestrator events to bridge clients
    58→    const forwardEvent = (event) => {
    59→      if (ws.readyState === 1) {
    60→        ws.send(JSON.stringify({ type: 'event', event }));
    61→      }
    62→    };
    63→    orchestrator.on('event', forwardEvent);
    64→
    65→    ws.on('message', async (raw) => {
    66→      let msg;
    67→      try { msg = JSON.parse(raw); } catch { ws.send(JSON.stringify({ type: 'error', error: 'invalid JSON' })); return; }
    68→
    69→      try {
    70→        registerBridgeSession(msg.client);
    71→        let result;
    72→        switch (msg.action) {
    73→          case 'hello':
    74→            result = registerBridgeSession(msg.client || msg.payload || {});
    75→            break;
    76→          case 'getState':
    77→            result = orchestrator.getState();
    78→            break;
    79→          case 'createAgent':
    80→            result = orchestrator.createAgent(msg.payload || {});
    81→            break;
    82→          case 'removeAgent':
    83→            result = await orchestrator.removeAgent(msg.agentId);
    84→            break;
    85→          case 'startRun':
    86→            result = await orchestrator.startRun(msg.payload || {});
    87→            break;
    88→          case 'cancelRun':
    89→            result = await orchestrator.cancelRun(msg.runId);
    90→            break;
    91→          case 'startRelay':
    92→            result = await orchestrator.startRelay(msg.payload || {});
    93→            break;
    94→          case 'getDiff':
    95→            result = orchestrator.getAgentDiff(msg.agentId);
    96→            break;
    97→          case 'listAgents':
    98→            result = orchestrator.listAgents();
    99→            break;
   100→          default:
   101→            result = { error: `Unknown action: ${msg.action}` };
   102→        }
   103→        ws.send(JSON.stringify({ type: 'response', id: msg.id, result }));
   104→      } catch (err) {
   105→        ws.send(JSON.stringify({ type: 'error', id: msg.id, error: err.message }));
   106→      }
   107→    });
   108→
   109→    ws.on('close', () => {
   110→      console.log('[Bridge] Client disconnected');
   111→      orchestrator.removeListener('event', forwardEvent);
   112→    });
   113→  });
   114→}
   115→
   116→app.whenReady().then(() => {
   117→  orchestrator = new AgentOrchestrator(path.resolve(__dirname, '..'));
   118→  orchestrator.on('event', (payload) => {
   119→    if (mainWindow && !mainWindow.isDestroyed()) {
   120→      mainWindow.webContents.send('orchestrator:event', payload);
   121→    }
   122→  });
   123→  registerIpcHandlers();
   124→  startBridge();
   125→  createWindow();
   126→});
   127→
   128→app.on('window-all-closed', () => {
   129→  if (process.platform !== 'darwin') app.quit();
   130→});
   131→
   132→app.on('activate', () => {
   133→  if (BrowserWindow.getAllWindows().length === 0) createWindow();
   134→});
   135→
   136→app.on('before-quit', async (e) => {
   137→  if (orchestrator) {
   138→    e.preventDefault();
   139→    if (wss) wss.close();
   140→    await orchestrator.shutdown();
   141→    app.exit(0);
   142→  }
   143→});
   144→"}]},"parent_tool_use_id":"toolu_01AVWSBtJxdo8rvwUiKxMVF9","session_id":"ee544de0-42a7-467b-9a7f-17b5aa67f0c9","uuid":"d8740a41-9775-44fe-9bed-ddfbb71aa1c8"}

{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01YBnjWb7xh7mvXpMFa1LcHM","type":"tool_result","content":"     1→#!/usr/bin/env node
     2→// ClawCraft Bridge CLI — send commands to running Electron app via WebSocket
     3→// Usage: node bridge.js <action> [JSON args]
     4→// Examples:
     5→//   node bridge.js getState
     6→//   node bridge.js createAgent '{"engine":"claude","name":"Claude-01"}'
     7→//   node bridge.js startRun '{"agentId":"1","prompt":"Fix the bug in app.js"}'
     8→//   node bridge.js listAgents
     9→//   node bridge.js getDiff 1
    10→//   node bridge.js removeAgent 1
    11→
    12→const WebSocket = require('ws');
    13→const BRIDGE_URL = 'ws://localhost:9477';
    14→
    15→function sanitizeToken(value) {
    16→  return String(value || '')
    17→    .trim()
    18→    .toLowerCase()
    19→    .replace(/[^a-z0-9._-]+/g, '-')
    20→    .replace(/^-+|-+$/g, '') || 'session';
    21→}
    22→
    23→function buildClientMeta() {
    24→  const threadId = process.env.CODEX_THREAD_ID || '';
    25→  const termSessionId = process.env.TERM_SESSION_ID || '';
    26→  const token = threadId || termSessionId || `pid-${process.pid}`;
    27→  const shortToken = String(token).slice(0, 8);
    28→  return {
    29→    sessionId: `codex-cli-${sanitizeToken(token)}`,
    30→    threadId,
    31→    termSessionId,
    32→    pid: process.pid,
    33→    name: 'Codex CLI',
    34→    engine: 'codex',
    35→    model: 'gpt-5',
    36→    role: 'assistant',
    37→    locked: true,
    38→    sessionKind: 'codex-cli',
    39→    taskTitle: `Talking with you in CLI ${shortToken}`,
    40→  };
    41→}
    42→
    43→const action = process.argv[2];
    44→if (!action) {
    45→  console.log('Usage: node bridge.js <action> [args]');
    46→  console.log('Actions: getState, listAgents, createAgent, removeAgent, startRun, cancelRun, startRelay, getDiff');
    47→  process.exit(1);
    48→}
    49→
    50→const arg = process.argv[3];
    51→let payload, agentId, runId;
    52→
    53→try {
    54→  if (action === 'removeAgent' || action === 'getDiff') {
    55→    agentId = arg;
    56→  } else if (action === 'cancelRun') {
    57→    runId = arg;
    58→  } else if (arg) {
    59→    payload = JSON.parse(arg);
    60→  }
    61→} catch {
    62→  payload = { prompt: arg };
    63→}
    64→
    65→const ws = new WebSocket(BRIDGE_URL);
    66→const msgId = Date.now().toString();
    67→const client = buildClientMeta();
    68→
    69→ws.on('open', () => {
    70→  const msg = { id: msgId, action };
    71→  msg.client = client;
    72→  if (payload) msg.payload = payload;
    73→  if (agentId) msg.agentId = agentId;
    74→  if (runId) msg.runId = runId;
    75→  ws.send(JSON.stringify(msg));
    76→});
    77→
    78→ws.on('message', (raw) => {
    79→  const data = JSON.parse(raw);
    80→  if (data.type === 'connected') return;
    81→  if (data.type === 'response' && data.id === msgId) {
    82→    console.log(JSON.stringify(data.result, null, 2));
    83→    ws.close();
    84→  }
    85→  if (data.type === 'error' && data.id === msgId) {
    86→    console.error('Error:', data.error);
    87→    ws.close();
    88→    process.exit(1);
    89→  }
    90→  if (data.type === 'event') {
    91→    // Stream events if waiting
    92→    const e = data.event;
    93→    if (e.type === 'run.phase') process.stderr.write(`[${e.phase}] ${e.label || ''} ${Math.round((e.progress||0)*100)}%\n`);
    94→    if (e.type === 'run.output') process.stderr.write(`[output] ${e.text?.slice(0,200)}\n`);
    95→    if (e.type === 'run.completed') { console.log('\n✅ Run completed'); ws.close(); }
    96→    if (e.type === 'run.failed') { console.error('\n❌ Run failed:', e.errorText); ws.close(); process.exit(1); }
    97→  }
    98→});
    99→
   100→ws.on('error', (err) => {
   101→  console.error('Connection failed. Is ClawCraft Electron app running? (npm start)');
   102→  console.error(err.message);
   103→  process.exit(1);
   104→});
   105→
   106→// Timeout
   107→setTimeout(() => { console.error('Timeout'); ws.close(); process.exit(1); }, 30000);
   108→"}]},"parent_tool_use_id":"toolu_01AVWSBtJxdo8rvwUiKxMVF9","session_id":"ee544de0-42a7-467b-9a7f-17b5aa67f0c9","uuid":"830afd8b-f70a-4408-ab3c-6636349a2a34"}

{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01QtdE2qqbj81KjxW5HXHuqH","type":"tool_result","content":"     1→const { EventEmitter } = require('events');
     2→const { spawn } = require('child_process');
     3→const path = require('path');
