     6→const { RunStore } = require('./run-store');
     7→const { WorkspaceManager } = require('./workspace-manager');
     8→const { AgentRegistry } = require('./agent-registry');
     9→const { MessageBus } = require('./message-bus');
    10→const { PromptCompiler } = require('./prompt-compiler');
    11→const { CodexAdapter } = require('../engines/codex-adapter');
    12→const { ClaudeAdapter } = require('../engines/claude-adapter');
    13→const { GeminiAdapter } = require('../engines/gemini-adapter');
