    24→function sanitizeSessionToken(value) {
    25→  return String(value || '')
    26→    .trim()
    27→    .toLowerCase()
    28→    .replace(/[^a-z0-9._-]+/g, '-')
    29→    .replace(/^-+|-+$/g, '') || 'session';
    30→}
    31→
    32→function buildSessionAgent(payload = {}) {
    33→  const token = payload.threadId || payload.termSessionId || payload.sessionId || payload.id || 'session';
    34→  const shortToken = String(token).slice(0, 8);
    35→  const sessionId = payload.sessionId || payload.id || `codex-cli-${sanitizeSessionToken(token)}`;
    36→  return {
    37→    id: sessionId,
    38→    name: payload.name || 'Codex CLI',
    39→    engine: payload.engine || 'codex',
    40→    model: payload.model || 'gpt-5',
    41→    role: payload.role || 'assistant',
