    44→    taskTitle: payload.taskTitle || `Talking with you in CLI ${shortToken}`,
    45→  };
    46→}
    47→
    48→function buildPrimarySessionAgent(env = process.env) {
    49→  const threadId = env.CODEX_THREAD_ID || '';
    50→  const termSessionId = env.TERM_SESSION_ID || '';
    51→  if (!threadId && !termSessionId) return null;
    52→  return buildSessionAgent({
    53→    threadId,
    54→    termSessionId,
    55→    name: 'Codex CLI',
    56→    sessionKind: 'codex-cli',
    57→  });
