    59→
    60→class AgentOrchestrator extends EventEmitter {
    61→  constructor(projectRoot) {
    62→    super();
    63→    this.projectRoot = projectRoot;
    64→    this.workspaceManager = new WorkspaceManager(this.projectRoot);
    65→    this.runStore = new RunStore(path.join(this.projectRoot, '.clawcraft', 'runs'));
    66→    this.registry = new AgentRegistry();
    67→    this.messageBus = new MessageBus(path.join(this.projectRoot, '.clawcraft', 'shared'));
    68→    this.promptCompiler = new PromptCompiler(this.registry, this.messageBus, path.join(this.projectRoot, '.clawcraft', 'shared'));
    69→    this.adapters = new Map([
    70→      ['codex', new CodexAdapter()],
    71→      ['claude', new ClaudeAdapter()],
    72→      ['gemini', new GeminiAdapter()],
    73→    ]);
    74→    // Legacy compat: this.agents delegates to registry
    75→    this.agents = this.registry.agents;
    76→    this.activeRuns = new Map();
    77→    this.agentsFile = path.join(this.projectRoot, '.clawcraft', 'agents.json');
    78→    // Forward message bus events
    79→    this.messageBus.on('message', (msg) => {
    80→      this.emitEvent({ type: 'agent.message', message: msg });
    81→    });
    82→    // Restore agents from previous session, then clean orphans
    83→    this._restoreAgents();
    84→    this._pruneLegacySessionAgents();
    85→    this._ensurePrimarySessionAgent();
    86→    const knownIds = new Set(this.agents.keys());
    87→    this.workspaceManager.cleanupOrphanWorktrees(knownIds);
    88→  }
    89→
    90→  _restoreAgents() {
    91→    const fs = require('fs');
    92→    if (!fs.existsSync(this.agentsFile)) return;
    93→    try {
    94→      const data = JSON.parse(fs.readFileSync(this.agentsFile, 'utf8'));
    95→      for (const agent of data) {
    96→        const adapter = this.adapters.get(agent.engine || 'codex');
    97→        agent.available = adapter ? adapter.isAvailable() : false;
    98→        agent.workspace = this.workspaceManager.getWorkingContext(String(agent.id));
    99→        this.registry.register(agent);
   100→      }"}]},"parent_tool_use_id":"toolu_01AVWSBtJxdo8rvwUiKxMVF9","session_id":"ee544de0-42a7-467b-9a7f-17b5aa67f0c9","uuid":"d4f9e91d-2fc3-4f6c-8dae-f2630fc8541d"}

