   120→  _persistAgents() {
   121→    const fs = require('fs');
   122→    fs.writeFileSync(this.agentsFile, JSON.stringify(this.registry.toJSON(), null, 2));
   123→  }
   124→
   125→  listAgents() {
   126→    return this.registry.list();
   127→  }
   128→
   129→  getEngineStatuses() {
   130→    return [...this.adapters.values()].map((adapter) => adapter.describe());
   131→  }
   132→
   133→  getState() {
   134→    return {
   135→      agents: this.listAgents(),
   136→      runs: this.runStore.listRuns(),
   137→      engines: this.getEngineStatuses(),
   138→      liveMode: true,
   139→      parallelMode: 'git-worktree',
   140→      collaborationModes: ['solo', 'shared-brief', 'relay'],
   141→    };
   142→  }
   143→
   144→  // 4단계: Relay mode — chain agents sequentially, each gets previous output
   145→  async startRelay(payload) {
   146→    const { agentIds, prompt, taskTitle } = payload;
   147→    if (!agentIds || agentIds.length < 2) throw new Error('Relay에는 2개 이상의 에이전트가 필요합니다.');
   148→    const results = [];
   149→    let currentPrompt = prompt;
   150→    for (const agentId of agentIds) {
   151→      const agent = this.agents.get(String(agentId));
   152→      if (!agent) { results.push({ agentId, status: 'skipped', error: 'agent not found' }); continue; }
   153→      try {
   154→        const run = await this.startRun({ agentId: String(agentId), prompt: currentPrompt, taskTitle });
   155→        // Wait for run to complete
   156→        await new Promise((resolve, reject) => {
   157→          const handler = (event) => {
   158→            const eid = event.run?.id || event.runId;
   159→            if (eid !== run.id) return;
   160→            if (event.type === 'run.completed') { this.removeListener('event', handler); resolve(event); }
   161→            if (event.type === 'run.failed') { this.removeListener('event', handler); reject(new Error(event.errorText || 'failed')); }
   162→            if (event.type === 'run.cancelled') { this.removeListener('event', handler); reject(new Error('cancelled')); }
   163→          };
   164→          this.on('event', handler);
   165→        });
   166→        const finishedRun = this.runStore.getRun(run.id);
   167→        const summary = finishedRun?.summary || '';
   168→        results.push({ agentId, status: 'done', summary });
   169→        // Next agent gets previous agent's output as context
   170→        currentPrompt = `## Previous Agent Output (${agent.name})\n${summary}\n\n---\n\n## Task\n${prompt}`;
   171→      } catch (err) {
   172→        results.push({ agentId, status: 'failed', error: err.message });
   173→        break; // Stop relay chain on failure
   174→      }
   175→    }
   176→    return results;
   177→  }
   178→
   179→  createAgent(payload = {}) {
   180→    const id = payload.id ?? `${Date.now()}`;
   181→    const engine = payload.engine || 'codex';
   182→    const adapter = this.adapters.get(engine);
   183→    const workspace = this.workspaceManager.getWorkingContext(String(id));
   184→    const agent = this.registry.register({
   185→      ...payload,
   186→      id,
   187→      engine,
   188→      available: adapter ? adapter.isAvailable() : false,
   189→      workspace,
   190→    });
   191→    this._persistAgents();
   192→    this.emitEvent({ type: 'agent.created', agent });
   193→    return agent;
   194→  }
