    22→    let ctx = '';
    23→
    24→    // Identity
    25→    const me = presence.self;
    26→    ctx += `You are SCV **${me.name}** (ID: ${me.id}).\n`;
    27→    ctx += `Engine: ${me.engine}, Model: ${me.model}, Role: ${me.role}, Team: ${me.teamId}\n\n`;
    28→
    29→    // Teammates
    30→    if (presence.teammates.length > 0) {
    31→      ctx += `## Visible teammates\n`;
    32→      presence.teammates.forEach(t => {
    33→        const statusMap = { running: 'working', idle: 'idle', failed: 'failed' };
    34→        ctx += `- **${t.name}** (ID:${t.id}) — ${t.engine}/${t.model}, status=${statusMap[t.status] || t.status}`;
    35→        if (t.taskTitle && t.taskTitle !== 'Waiting') ctx += `, task="${t.taskTitle}"`;
    36→        ctx += '\n';
    37→      });
    38→      ctx += '\n';
    39→    }
    40→
    41→    // Project brief
    42→    const briefPath = path.join(this.sharedDir, 'brief.md');
    43→    if (fs.existsSync(briefPath)) {
    44→      const brief = fs.readFileSync(briefPath, 'utf8').trim();
    45→      if (brief.length > 20) ctx += `## Project Brief\n${brief}\n\n`;
    46→    }
    47→
    48→    // Decision log
    49→    const decPath = path.join(this.sharedDir, 'decision-log.md');
    50→    if (fs.existsSync(decPath)) {
    51→      const dec = fs.readFileSync(decPath, 'utf8').trim();
    52→      if (dec.length > 20) ctx += `## Decision Log\n${dec}\n\n`;
    53→    }
    54→
    55→    // Recent radio (team conversation)
    56→    const messages = this.messageBus.getConversationFor(agentId, 10);
    57→    if (messages.length > 0) {
    58→      ctx += `## Recent radio\n`;
    59→      messages.forEach(m => {
    60→        const sender = m.fromName || m.from;
    61→        const kindTag = m.kind !== 'chat' ? ` [${m.kind}]` : '';
    62→        ctx += `- **${sender}**${kindTag}: ${(m.text || '').slice(0, 200)}\n`;
    63→      });
    64→      ctx += '\n';
    65→    }
    66→
    67→    // Instructions
    68→    ctx += `## Communication rules\n`;
    69→    ctx += `- Your messages are shared with teammates via the radio channel.\n`;
    70→    ctx += `- Mention teammates by name when coordinating.\n`;
    71→    ctx += `- Report completion, failures, or blockers.\n\n`;
    72→
    73→    ctx += `---\n\n## Current objective\n${taskPrompt}`;
    74→    return ctx;
    75→  }
    76→}
