    59→    agent.applyRunPhase(event.phase,event.progress,event.label);
    60→    return;
    61→  }
    62→  if(event.type==='run.output'){
    63→    agent.applyRunPhase(event.phase,event.progress,agent.runLabel);
    64→    agent.appendRunLog(event.text);
    65→    return;
    66→  }
    67→  if(event.type==='run.completed'){
    68→    agent.finishRun('done',event.run);
    69→    return;
