    74→    agent.finishRun('failed',event.run);
    75→    return;
    76→  }
    77→  if(event.type==='run.cancelled'){
    78→    agent.finishRun('cancelled',event.run);
    79→  }
    80→}"}]},"parent_tool_use_id":"toolu_01AVWSBtJxdo8rvwUiKxMVF9","session_id":"ee544de0-42a7-467b-9a7f-17b5aa67f0c9","uuid":"1b119687-01fa-44c7-a59d-b88699ee3fda"}

