"drawer-section\\\">\\n      <h4>실행 로그</h4>\\n      <pre id=\\\"drawer-logs\\\">(아직 없음)</pre>\\n    </div>\\n    <div class=\\\"drawer-section\\\">\\n      <h4>변경 Diff</h4>\\n      <pre id=\\\"drawer-diff\\\" style=\\\"max-height:120px\\\">(작업 완료 후 표시됩니다)</pre>\\n      <button id=\\\"drawer-load-diff\\\" class=\\\"btn\\\" style=\\\"margin-top:4px;padding:3px 8px;font-size:9px\\\">Diff 로드</button>\\n    </div>\\n  </div>\\n</aside>\\n\\n<script src=\\\"audio.js\\\"></script>\\n<script src=\\\"ui-panels.js\\\"></script>\\n<script src=\\\"live-state.js\\\"></script>\\n<script>\\n// ═══════════════════════════════════════════════════════════════\\n// SCV AGENT ANIMATION — Canvas Game Engine (core rendering + Agent class)\\n// ═══════════════════════════════════════════════════════════════\\n\\nconst MOVE_SPEED=165,PATROL_SPEED=75,MINING_SPEED=132,BUILD_SPEED=0.06,TILE=32;\\nconst MINING_ACCEL=2.7; // 3x slower accel/decel for mining trips\\nconst MINING_PAUSE=6; // seconds to mine at mineral\\nconst MAP_IMG_W=2272,MAP_IMG_H=1420;\\nconst BLDG_TYPES=[\\n  {id:'command_center',name:'커맨드센터',w:127,h:103,color:'#8a5a4a',colorR:138,colorG:90,colorB:74},\\n];\\n// === SCV Sprite Atlas ===\\nconst SCV_CELL=42,SCV_ROW_H=49,SCV_SCALE=1.0;\\nconst SCV_DIR16=[\\n  [4,false],[5,false],[6,false],[7,false],[8,false],\\n  [7,true],[6,true],[5,true],[4,true],[3,true],\\n  [2,true],[1,true],[0,false],[1,false],[2,false],[3,false]\\n];\\nconst SCV_TURN_RATE=55;\\nconst SCV_ACCEL=8;\\nconst SCV_DECEL_DIST=30;\\nlet scvImg=null;\\n// Command Center construction stages (row 1 of buildings.png)\\nconst CC_STAGES=[\\n  {x:11,  w:62},   // stage 1: foundation\\n  {x:119, w:61},   // stage 2\\n  {x:224, w:108},  // stage 3\\n  {x:347, w:121},  // stage 4\\n  {x:481, w:127},  // stage 5\\n  {x:610, w:127},  // stage 6: complete\\n];\\nconst CC_Y=7,CC_H=103;\\n// Barracks (row 2, kept for reference)\\nconst BARR_STAGES=[\\n  {x:16,  w:59},{x:124,w:60},{x:228,w:108},{x:370,w:115},{x:502,w:124},{x:644,w:124},\\n];\\nconst BARR_Y=135,BARR_H=111;\\n// CC flicker pattern when working: irregular 5/6 switching\\nconst CC_FLICKER_CYCLES=[[4,4,4,5],[4,4,5],[4,5]];\\nlet mineralImg=null;\\nlet bldgImg=null;\\nconst canvas=document.getElementById('game-canvas');\\nconst ctx=canvas.getContext('2d');\\nconst miniCanvas=document.getElementById('minimap');\\nconst miniCtx=miniCanvas.getContext('2d');\\nlet W,H,WORLD_W=1200,WORLD_H=750,cam={x:0,y:0},keys={},mouse={down:false,px:0,py:0,button:-1};\\nlet agents=[],nextId=1,time=0,lastT=0,dt=0;\\n\\n// ═══════════════════════════════════════════════════════════════\\n// SC1 SELECTION & COMMAND STATE\\n// ═══════════════════════════════════════════════════════════════\\nlet selectedAgents=new Set();\\nlet dragBox=null;\\nlet moveMarkers=[];\\nlet mouseScreenX=0,mouseScreenY=0;\\nlet cursorOnCanvas=false;\\nconst MANUAL_IDLE_TIME=5;\\n\\nfunction resize(){W=window.innerWidth-260;H=window.innerHeight-44;canvas.width=W;canvas.height=H;WORLD_W=W;WORLD_H=H;miniCanvas.width=160;miniCanvas.height=100;}\\nwindow.addEventListener('resize',resize);resize();\\n\\n// ═══════════════════════════════════════════════════════════════\\n// DRAWING\\n// ═══════════════════════════════════════════════════════════════\\nfunction rr(x,y,w,h,r){\\n  ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);\\n  ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);ctx.lineTo(x+r,y+h);\\n  ctx.quadraticCurveTo(x,y+h,x,y+h-r);ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);ctx.fill();\\n}\\nfunction rrs(x,y,w,h,r){\\n  ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);\\n  ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);ctx.lineTo(x+r,y+h);\\n  ctx.quadraticCurveTo(x,y+h,x,y+h-r);ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);ctx.stroke();\\n}\\nfunction label(x,y,t,c,sz){\\n  ctx.font=(sz||10)+'px Consolas,monospace';ctx.textAlign='center';\\n  ctx.strokeStyle='#000';ctx.lineWidth=2.5;ctx.strokeText(t,x,y);\\n  ctx.fillStyle=c;ctx.fillText(t,x,y);\\n}\\n\\n// Load sprite images\\nlet mapImg=null,cursorImg=null,hoverCursorImg=null,arrowCursorImg=null,gasImg=null,waterMaskImg=null;\\nlet moveMarkerImgs=[null,null,null]; // small, medium, large\\n// Vespene gas animation: 8 frames, 28px cells\\nconst GAS_FRAMES=8,GAS_CELL=28,GAS_H=34,GAS_FPS=8,GAS_SCALE=1.75,GAS_CYCLE_PAUSE=2;\\n// Geyser position as fraction of map image, each with independent animation\\nconst GEYSER_POS=[\\n  {mx:0.4,my:0.69,frame:0,ft:0,paused:false,pt:0},\\n  {mx:0.44,my:0.68,frame:0,ft:0,paused:true,pt:GAS_CYCLE_PAUSE-0.8},\\n];\\nfunction loadScvSprite(){\\n  scvImg=new Image(); scvImg.src='./assets/scv_shadow_atlas.png';\\n  mapImg=new Image(); mapImg.src='./assets/map.png';\\n  bldgImg=new Image(); bldgImg.src='./assets/buildings.png';\\n  cursorImg=new Image(); cursorImg.src='./assets/sc_cursor_webp_0.png';\\n  hoverCursorImg=new Image(); hoverCursorImg.src='./assets/sc_cursor_green_circle_spritesheet.png';\\n  arrowCursorImg=new Image(); arrowCursorImg.src='./assets/sc1_green_arrow_spritesheet.png';\\n  gasImg=new Image(); gasImg.src='./assets/vespene_gas.png';\\n  waterMaskImg=new Image(); waterMaskImg.src='./assets/water_mask.png';\\n  mineralImg=new Image(); mineralImg.src='./assets/mineral_real.png';\\n  moveMarkerImgs[0]=new Image(); moveMarkerImgs[0].src='./assets/sc1_move_marker_small.png';\\n  moveMarkerImgs[1]=new Image(); moveMarkerImgs[1].src='./assets/sc1_move_marker_medium.png';\\n  moveMarkerImgs[2]=new Image(); moveMarkerImgs[2].src='./assets/sc1_move_marker_large.png';\\n}\\n\\nfunction drawScvSprite(cx,cy,dir16,frame){\\n  if(!scvImg||!scvImg.complete||!scvImg.naturalWidth) return;\\n  const di=((Math.round(dir16)%16)+16)%16;\\n  const [col,flip]=SCV_DIR16[di];\\n  const sx=col*SCV_CELL;\\n  const dw=SCV_CELL*SCV_SCALE;\\n  const dh=SCV_ROW_H*SCV_SCALE;\\n  const px=Math.round(cx),py=Math.round(cy);\\n  ctx.save();\\n  ctx.translate(px,py);\\n  if(flip)ctx.scale(-1,1);\\n  ctx.drawImage(scvImg,sx,0,SCV_CELL,SCV_ROW_H,-dw/2,-dh+10,dw,dh);\\n  ctx.restore();\\n}\\n\\nfunction drawBarracks(bx,by,stageIdx){\\n  if(!bldgImg||!bldgImg.complete||!bldgImg.naturalWidth) return;\\n  const s=BARR_STAGES[Math.min(stageIdx,5)];\\n  const scale=0.8;\\n  const dw=s.w*scale,dh=BARR_H*scale;\\n  ctx.drawImage(bldgImg,s.x,BARR_Y,s.w,BARR_H,bx-dw/2,by-dh+14,dw,dh);\\n}\\n\\n\",\"exit_code\":0,\"status\":\"completed\"}}","at":"2026-03-16T08:16:29.412Z"}
