dex.html || start src/index.html\\\"\\nREADME.md:15:│   └── index.html            # ★ 전체 앱 (Canvas + WebAudio, 단일 파일)\\nREADME.md:22:# src/index.html 을 브라우저에서 열기\\nREADME.md:23:open src/index.html        # macOS\\nREADME.md:24:xdg-open src/index.html    # Linux\\nREADME.md:25:start src/index.html       # Windows\\nsrc/main.js:24:  mainWindow.loadFile(path.join(__dirname, 'index.html'));\\n\",\"exit_code\":0,\"status\":\"completed\"}}","at":"2026-03-16T08:16:47.560Z"}
