*{margin:0;padding:0;box-sizing:border-box}

:root{
  --bg-deep:#080818;
  --bg-panel:rgba(8,20,44,.92);
  --accent:#4a9eff;
  --accent-glow:rgba(74,158,255,.35);
  --gold:#f0a030;
  --green:#30d060;
  --text:#c2ddff;
  --text-dim:#5a8abf;
  --border:#1a3a6a;
}

html{scroll-behavior:smooth}
body{
  background:var(--bg-deep);
  color:var(--text);
  font-family:'Consolas','Courier New','Fira Code',monospace;
  line-height:1.6;
  overflow-x:hidden;
}

/* Starfield background */
body::before{
  content:'';position:fixed;inset:0;z-index:-1;
  background:
    radial-gradient(1px 1px at 10% 20%,rgba(74,158,255,.6),transparent),
    radial-gradient(1px 1px at 30% 60%,rgba(240,160,48,.4),transparent),
    radial-gradient(1px 1px at 50% 10%,rgba(48,208,96,.5),transparent),
    radial-gradient(1px 1px at 70% 80%,rgba(74,158,255,.5),transparent),
    radial-gradient(1px 1px at 90% 40%,rgba(255,255,255,.4),transparent),
    radial-gradient(1px 1px at 15% 85%,rgba(74,158,255,.3),transparent),
    radial-gradient(1px 1px at 45% 35%,rgba(240,160,48,.3),transparent),
    radial-gradient(1px 1px at 80% 15%,rgba(48,208,96,.4),transparent),
    radial-gradient(1px 1px at 25% 45%,rgba(255,255,255,.3),transparent),
    radial-gradient(1px 1px at 60% 70%,rgba(74,158,255,.4),transparent),
    radial-gradient(1px 1px at 5% 55%,rgba(240,160,48,.35),transparent),
    radial-gradient(1px 1px at 95% 25%,rgba(48,208,96,.3),transparent);
}

/* ─── HERO ─── */
.hero{
  min-height:100vh;display:flex;flex-direction:column;
  align-items:center;justify-content:center;text-align:center;
  padding:40px 20px;position:relative;
}
.hero::after{
  content:'';position:absolute;bottom:0;left:0;right:0;height:120px;
  background:linear-gradient(transparent,var(--bg-deep));
}
.hero-badge{
  display:inline-block;padding:6px 16px;border-radius:20px;
  background:rgba(74,158,255,.1);border:1px solid var(--border);
  color:var(--accent);font-size:12px;letter-spacing:2px;
  text-transform:uppercase;margin-bottom:24px;
}
.hero h1{
  font-size:clamp(40px,8vw,80px);color:#fff;
  text-shadow:0 0 40px var(--accent-glow);
  letter-spacing:4px;margin-bottom:8px;
}
.hero h1 span{color:var(--accent)}
.hero .subtitle{
  font-size:clamp(14px,2.5vw,20px);color:var(--text-dim);
  max-width:600px;margin-bottom:40px;
}
.hero-buttons{display:flex;gap:16px;flex-wrap:wrap;justify-content:center}
.btn-primary,.btn-secondary{
  padding:14px 32px;font-size:14px;font-family:inherit;
  border-radius:3px;cursor:pointer;transition:all .2s;
  letter-spacing:1px;text-decoration:none;display:inline-block;
}
.btn-primary{
  background:linear-gradient(180deg,#2a5a9a,#1a3a6a);
  border:1px solid var(--accent);color:#fff;
}
.btn-primary:hover{
  background:linear-gradient(180deg,#3a7acc,#2a5a9a);
  box-shadow:0 0 20px var(--accent-glow);
}
.btn-secondary{
  background:transparent;border:1px solid var(--border);color:var(--text);
}
.btn-secondary:hover{
  border-color:var(--accent);color:#fff;
}

/* ─── SECTIONS ─── */
section{padding:80px 20px;max-width:1100px;margin:0 auto}
.section-title{
  text-align:center;font-size:32px;color:#fff;margin-bottom:12px;
  text-shadow:0 0 20px var(--accent-glow);
}
.section-sub{
  text-align:center;color:var(--text-dim);font-size:14px;
  margin-bottom:48px;max-width:600px;margin-left:auto;margin-right:auto;
}

/* ─── FEATURE GRID ─── */
.feature-grid{
  display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));
  gap:24px;
}
.feature-card{
  background:var(--bg-panel);border:1px solid var(--border);
  border-radius:4px;padding:28px;transition:all .3s;
}
.feature-card:hover{
  border-color:var(--accent);transform:translateY(-4px);
  box-shadow:0 8px 30px rgba(0,0,0,.4);
}
.feature-icon{
  font-size:28px;margin-bottom:16px;display:block;
}
.feature-card h3{
  color:var(--accent);font-size:16px;margin-bottom:8px;
}
.feature-card p{
  color:var(--text-dim);font-size:13px;line-height:1.7;
}

/* ─── ARCHITECTURE ─── */
.arch-diagram{
  background:var(--bg-panel);border:1px solid var(--border);
  border-radius:4px;padding:32px;overflow-x:auto;
}
.arch-diagram pre{
  color:var(--accent);font-size:13px;line-height:1.8;
  white-space:pre;
}

/* ─── AGENT CARDS ─── */
.agent-showcase{
  display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));
  gap:20px;
}
.agent-card{
  background:var(--bg-panel);border:1px solid var(--border);
  border-radius:4px;padding:24px;text-align:center;
  transition:all .3s;position:relative;overflow:hidden;
}
.agent-card::before{
  content:'';position:absolute;top:0;left:0;right:0;height:3px;
}
.agent-card.codex::before{background:var(--green)}
.agent-card.claude::before{background:var(--accent)}
.agent-card.gemini::before{background:var(--gold)}
.agent-card:hover{border-color:var(--accent);transform:translateY(-2px)}
.agent-card .engine-name{
  font-size:20px;color:#fff;font-weight:bold;margin-bottom:4px;
}
.agent-card .engine-model{
  font-size:12px;color:var(--text-dim);margin-bottom:12px;
}
.agent-card .engine-desc{
  font-size:12px;color:var(--text-dim);line-height:1.6;
}

/* ─── CODE BLOCK ─── */
.code-block{
  background:rgba(4,16,36,.95);border:1px solid var(--border);
  border-radius:4px;padding:24px;overflow-x:auto;margin-top:24px;
}
.code-block code{
  color:var(--text);font-size:13px;line-height:1.7;
  white-space:pre;
}
.code-comment{color:var(--text-dim)}
.code-keyword{color:var(--accent)}
.code-string{color:var(--green)}
.code-func{color:var(--gold)}

/* ─── STATS ─── */
.stats-row{
  display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));
  gap:20px;margin-bottom:48px;
}
.stat-item{
  text-align:center;padding:24px;background:var(--bg-panel);
  border:1px solid var(--border);border-radius:4px;
}
.stat-num{
  font-size:36px;color:var(--accent);font-weight:bold;
  text-shadow:0 0 15px var(--accent-glow);
}
.stat-label{font-size:12px;color:var(--text-dim);margin-top:4px}

/* ─── FOOTER ─── */
footer{
  text-align:center;padding:40px 20px;
  border-top:1px solid var(--border);color:var(--text-dim);
  font-size:12px;
}
footer a{color:var(--accent);text-decoration:none}
footer a:hover{text-decoration:underline}

/* ─── SCROLL ANIMATION ─── */
.fade-in{opacity:0;transform:translateY(20px);transition:all .6s ease-out}
.fade-in.visible{opacity:1;transform:translateY(0)}

/* ─── RESPONSIVE ─── */
@media(max-width:640px){
  .hero h1{letter-spacing:2px}
  .feature-grid{grid-template-columns:1fr}
  .agent-showcase{grid-template-columns:1fr}
  section{padding:60px 16px}
}
