  background:var(--bg-panel);border:1px solid var(--border);
  border-radius:4px;padding:24px;text-align:center;
  transition:all .3s;position:relative;overflow:hidden;
}
.agent-card::before{
  content:'';position:absolute;top:0;left:0;right:0;height:3px;
}
.agent-card.codex::before{background:var(--green)}
.agent-card.claude::before{background:var(--accent)}
.agent-card.gemini::before{background:var(--gold)}
.agent-card:hover{border-color:var(--accent);transform:translateY(-2px)}
.agent-card .engine-name{
  font-size:20px;color:#fff;font-weight:bold;margin-bottom:4px;
}
.agent-card .engine-model{
  font-size:12px;color:var(--text-dim);margin-bottom:12px;
}
.agent-card .engine-desc{
  font-size:12px;color:var(--text-dim);line-height:1.6;
}

/* ─── CODE BLOCK ─── */
.code-block{
  background:rgba(4,16,36,.95);border:1px solid var(--border);
  border-radius:4px;padding:24px;overflow-x:auto;margin-top:24px;
}
.code-block code{
  color:var(--text);font-size:13px;line-height:1.7;
  white-space:pre;
}
.code-comment{color:var(--text-dim)}
.code-keyword{color:var(--accent)}
.code-string{color:var(--green)}
.code-func{color:var(--gold)}

/* ─── STATS ─── */
.stats-row{
  display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));
  gap:20px;margin-bottom:48px;
}
.stat-item{
  text-align:center;padding:24px;background:var(--bg-panel);
  border:1px solid var(--border);border-radius:4px;
}
.stat-num{
  font-size:36px;color:var(--accent);font-weight:bold;
  text-shadow:0 0 15px var(--accent-glow);
}
.stat-label{font-size:12px;color:var(--text-dim);margin-top:4px}

/* ─── FOOTER ─── */
footer{
  text-align:center;padding:40px 20px;
  border-top:1px solid var(--border);color:var(--text-dim);
  font-size:12px;
}
footer a{color:var(--accent);text-decoration:none}
footer a:hover{text-decoration:underline}

/* ─── SCROLL ANIMATION ─── */
.fade-in{opacity:0;transform:translateY(20px);transition:all .6s ease-out}
.fade-in.visible{opacity:1;transform:translateY(0)}

/* ─── RESPONSIVE ─── */
@media(max-width:640px){
  .hero h1{letter-spacing:2px}
  .feature-grid{grid-template-columns:1fr}
  .agent-showcase{grid-template-columns:1fr}
  section{padding:60px 16px}
}
